const payload = $json.body ?? $json;

const contactId = payload.contact_id ?? payload.contactId ?? null;
const dealId = payload.deal_id ?? payload.dealId ?? null;
const product = payload.product_name ?? payload.produto ?? null;
const value = Number(payload.product_value ?? payload.value ?? 0);

if (!contactId || !dealId) {
  throw new Error('Payload invalido: contact_id e deal_id sao obrigatorios.');
}

return [
  {
    json: {
      status: 'bootstrap_ready',
      message: 'Webhook Clint Won validado. Integracoes com Google Sheets e Slack entram na proxima fase.',
      received_at: new Date().toISOString(),
      contact_id: contactId,
      deal_id: dealId,
      product_name: product,
      product_value: value
    }
  }
];
